
let currentLang = 'de';

function setLang(lang) {
  currentLang = lang;
  document.querySelectorAll('.lang-toggle button').forEach((b,i) => {
    b.classList.toggle('active', (i === 0 && lang === 'de') || (i === 1 && lang === 'en'));
  });
  document.querySelectorAll('[data-de]').forEach(el => {
    const text = el.getAttribute('data-' + lang);
    if(el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') {
      el.placeholder = text;
    } else {
      el.innerHTML = text;
    }
  });
}

function openModal(title, price) {
  document.getElementById('modal-title').textContent = title;
  document.getElementById('modal-price').textContent = price;
  document.getElementById('card-form').classList.remove('open');
  document.getElementById('paypal-form').style.display = 'none';
  document.getElementById('modal').classList.add('open');
}
function closeModal() {
  document.getElementById('modal').classList.remove('open');
}
function selectCard() {
  document.getElementById('card-form').classList.add('open');
  document.getElementById('paypal-form').style.display = 'none';
}
function selectPayPal() {
  document.getElementById('paypal-form').style.display = 'block';
  document.getElementById('card-form').classList.remove('open');
}
function pay() {
  alert(currentLang === 'de'
    ? '✓ Vielen Dank! In einer echten Integration würde hier die Zahlung verarbeitet.'
    : '✓ Thank you! In a live integration, payment would be processed here.');
  closeModal();
}
function sendMsg() {
  alert(currentLang === 'de'
    ? '✓ Nachricht gesendet! Denis meldet sich bald bei dir.'
    : '✓ Message sent! Denis will get back to you soon.');
}


