function renderPaintings() {
  const grid = document.getElementById('paintings-grid');
  if (!grid || typeof allPaintings === 'undefined') return;
  grid.innerHTML = '';

  allPaintings.forEach((p) => {
    const div = document.createElement('div');
    div.className = 'shop-item painting-item';
    div.dataset.type = 'verkauf';

    const imgWrap = document.createElement('div');
    imgWrap.className = 'painting-img';

    const img = document.createElement('img');
    img.src = p.img;
    img.alt = p.title || 'Artwork';
    img.loading = 'lazy';
    imgWrap.appendChild(img);

    imgWrap.addEventListener('click', () => {
      if (typeof openLightbox === 'function') {
        openLightbox(p.img, `${p.title || ''} · ${p.medium || ''}`);
      }
    });

    const info = document.createElement('div');
    info.className = 'shop-info';

    const title = document.createElement('h3');
    title.textContent = p.title || 'Artwork';

    const medium = document.createElement('p');
    medium.style.fontSize = '0.82rem';
    medium.textContent = p.medium || '';

    const price = document.createElement('div');
    price.className = 'shop-price';
    price.textContent = p.price || 'CHF 250';

    const btn = document.createElement('button');
    btn.className = 'shop-buy';
    btn.setAttribute('data-de', 'In den Warenkorb');
    btn.setAttribute('data-en', 'Add to Cart');
    btn.textContent = (window.currentLang === 'en') ? 'Add to Cart' : 'In den Warenkorb';
    btn.addEventListener('click', () => {
      if (typeof openModal === 'function') openModal(p.title || 'Artwork', p.price || 'CHF 250');
    });

    info.appendChild(title);
    info.appendChild(medium);
    info.appendChild(price);
    info.appendChild(btn);

    div.appendChild(imgWrap);
    div.appendChild(info);
    grid.appendChild(div);
  });
}



function filterShop(type) {
  document.querySelectorAll('.filter-btn').forEach(btn => btn.classList.remove('active'));

  // activate clicked button by text/data or onclick content
  document.querySelectorAll('.filter-btn').forEach(btn => {
    const oc = btn.getAttribute('onclick') || '';
    if (oc.includes(`'${type}'`) || oc.includes(`"${type}"`)) btn.classList.add('active');
  });

  const paintings = document.querySelectorAll('#paintings-grid .shop-item');
  const services = document.querySelectorAll('.services-shop .shop-item');

  if (type === 'all') {
    paintings.forEach(item => item.style.display = '');
    services.forEach(item => item.style.display = '');
  } else if (type === 'verkauf') {
    paintings.forEach(item => item.style.display = '');
    services.forEach(item => item.style.display = 'none');
  } else if (type === 'services') {
    paintings.forEach(item => item.style.display = 'none');
    services.forEach(item => item.style.display = '');
  }
}


function openLightbox(src, caption) {
  document.getElementById('lightbox-img').src = src;
  document.getElementById('lightbox-caption').textContent = caption;
  document.getElementById('lightbox').classList.add('open');
  document.body.style.overflow = 'hidden';
}
function closeLightbox(e) {
  if(e && e.target === document.getElementById('lightbox-img')) return;
  document.getElementById('lightbox').classList.remove('open');
  document.body.style.overflow = '';
}
document.addEventListener('keydown', e => { if(e.key === 'Escape') closeLightbox(); });



window.currentLang = window.currentLang || 'de';
window.currentProduct = {title:'', price:''};

/** Backend URL – localhost uses Express server; production uses same origin (Netlify Functions). */
const STRIPE_API_URL = window.STRIPE_API_URL || (
  location.hostname === 'localhost' || location.hostname === '127.0.0.1'
    ? 'http://localhost:4242'
    : window.location.origin
);

async function checkoutStripe() {
  const title = window.currentProduct.title;
  if (!title) return;

  const btn = document.getElementById('stripe-checkout-btn');
  const loadingDe = 'Weiterleitung…';
  const loadingEn = 'Redirecting…';
  const prevText = btn ? btn.textContent : '';

  if (btn) {
    btn.disabled = true;
    btn.textContent = window.currentLang === 'en' ? loadingEn : loadingDe;
  }

  try {
    const res = await fetch(`${STRIPE_API_URL}/api/create-checkout-session`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ title }),
    });
    const data = await res.json();
    if (!res.ok || !data.url) {
      throw new Error(data.error || 'Checkout failed');
    }
    window.location.href = data.url;
  } catch (err) {
    alert(window.currentLang === 'de'
      ? `Zahlung konnte nicht gestartet werden: ${err.message}`
      : `Could not start checkout: ${err.message}`);
    if (btn) {
      btn.disabled = false;
      btn.textContent = prevText;
    }
  }
}

function setLang(lang){
  window.currentLang = lang;
  document.documentElement.lang = lang === 'en' ? 'en' : 'de';
  document.querySelectorAll('.lang-toggle button').forEach(btn=>{
    btn.classList.toggle('active', btn.textContent.trim().toLowerCase() === lang);
  });
  document.querySelectorAll('[data-de]').forEach(el=>{
    const value = el.getAttribute('data-' + lang);
    if(!value) return;
    if(el.tagName === 'INPUT' || el.tagName === 'TEXTAREA'){
      el.placeholder = value;
    } else {
      el.innerHTML = value;
    }
  });
  updateOrderLinks();
}

function updateOrderLinks(){
  const title = window.currentProduct.title || '';
  const price = window.currentProduct.price || '';
  const subject = window.currentLang === 'en' ? `Inquiry / Order: ${title}` : `Anfrage / Bestellung: ${title}`;
  const body = window.currentLang === 'en'
    ? `Hello Denis,%0D%0A%0D%0AI am interested in: ${title}%0D%0APrice: ${price}%0D%0A%0D%0APlease confirm availability, payment and shipping.%0D%0A%0D%0AName:%0D%0AAddress:%0D%0APhone:%0D%0A`
    : `Hallo Denis,%0D%0A%0D%0AIch interessiere mich für: ${title}%0D%0APreis: ${price}%0D%0A%0D%0ABitte bestätige Verfügbarkeit, Zahlung und Versand.%0D%0A%0D%0AName:%0D%0AAdresse:%0D%0ATelefon:%0D%0A`;
  const mail = document.getElementById('order-mail-link');
  const wa = document.getElementById('order-whatsapp-link');
  if(mail){
    mail.href = `mailto:batinicdenis@gmail.com?subject=${encodeURIComponent(subject)}&body=${body}`;
    mail.textContent = window.currentLang === 'en' ? 'Inquire by email' : 'Per E-Mail anfragen';
  }
  if(wa){
    const text = window.currentLang === 'en'
      ? `Hello Denis, I am interested in ${title} (${price}). Please confirm availability, payment and shipping.`
      : `Hallo Denis, ich interessiere mich für ${title} (${price}). Bitte bestätige Verfügbarkeit, Zahlung und Versand.`;
    wa.href = `https://wa.me/41782282705?text=${encodeURIComponent(text)}`;
    wa.textContent = window.currentLang === 'en' ? 'WhatsApp inquiry' : 'WhatsApp Anfrage';
  }
}

function openModal(title, price){
  window.currentProduct = {title, price};
  document.getElementById('modal-title').textContent = title;
  document.getElementById('modal-price').textContent = price;
  updateOrderLinks();
  document.getElementById('modal').classList.add('open');
}
function closeModal(){
  const modal = document.getElementById('modal');
  if(modal) modal.classList.remove('open');
}

function scrollToShopArea(type){
  setTimeout(()=>{
    const target = type === 'services' ? document.querySelector('.services-shop') : document.getElementById('paintings-grid');
    if(target) target.scrollIntoView({behavior:'smooth', block:'start'});
  }, 50);
}

function jumpToSection(id){
  const el = document.getElementById(id);
  if(el) el.scrollIntoView({behavior:'smooth', block:'start'});
}

function openRefPopup(title,content){
  const titleEl = document.getElementById('refTitle');
  const contentEl = document.getElementById('refContent');
  const popup = document.getElementById('refPopup');
  if(titleEl) titleEl.innerHTML = title;
  if(contentEl) contentEl.innerHTML = content;
  if(popup) popup.classList.add('open');
}
function closeRefPopup(){
  const popup = document.getElementById('refPopup');
  if(popup) popup.classList.remove('open');
}

// Repair/override lightbox
window.openLightbox = function(src, caption){
  const img = document.getElementById('lightbox-img');
  const cap = document.getElementById('lightbox-caption');
  const lb = document.getElementById('lightbox');
  if(img) img.src = src;
  if(cap) cap.textContent = caption || '';
  if(lb) lb.classList.add('open');
  document.body.style.overflow = 'hidden';
};

// Repair renderPaintings if original JS had a broken onclick.
document.addEventListener('DOMContentLoaded', ()=>{
  setLang(window.currentLang || 'de');

  try {
    if (typeof allPaintings !== 'undefined') {
      const grid = document.getElementById('paintings-grid');
      if (grid) {
        grid.innerHTML = '';
        allPaintings.forEach((p) => {
          const div = document.createElement('div');
          div.className = 'shop-item';
          div.dataset.type = 'verkauf';
          const safeTitle = String(p.title || '').replace(/'/g, "\\'");
          const safeMedium = String(p.medium || '').replace(/'/g, "\\'");
          div.innerHTML = `
            <div class="painting-img">
              <img src="${p.img}" alt="${p.title}" loading="lazy">
            </div>
            <div class="shop-info">
              <h3>${p.title}</h3>
              <p style="font-size:0.82rem;">${p.medium}</p>
              <div class="shop-price">CHF 250</div>
              <button class="shop-buy" onclick="openModal('${safeTitle}', 'CHF 250')" data-de="In den Warenkorb" data-en="Add to Cart">In den Warenkorb</button>
            </div>`;
          div.querySelector('.painting-img').addEventListener('click', () => openLightbox(p.img, `${p.title} · ${p.medium}`));
          grid.appendChild(div);
        });
      }
    }
  } catch(e) {
    console.warn('Shop render repair skipped:', e);
  }

  const modal = document.getElementById('modal');
  if(modal){
    modal.addEventListener('click', e => { if(e.target === modal) closeModal(); });
  }
});



document.addEventListener('DOMContentLoaded', function(){
  try {
    if (typeof renderPaintings === 'function') renderPaintings();
    if (typeof filterShop === 'function') filterShop('all');
    if (typeof setLang === 'function') setLang(window.currentLang || 'de');
  } catch (e) {
    console.error('Shop initialization failed:', e);
  }
});
